commit-types.description:
List of commit types used for version calculation and changelog generation.
Default: [
  {
    "type": "feat",
    "section": "Features"
  },
  {
    "type": "fix",
    "section": "Bug Fixes"
  },
  {
    "type": "perf",
    "section": "Performance Improvements"
  },
  {
    "type": "revert",
    "section": "Reverts"
  },
  {
    "type": "docs",
    "section": "Documentation",
    "hidden": true
  },
  {
    "type": "style",
    "section": "Styles",
    "hidden": true
  },
  {
    "type": "chore",
    "section": "Miscellaneous Chores",
    "hidden": true
  },
  {
    "type": "refactor",
    "section": "Code Refactoring",
    "hidden": true
  },
  {
    "type": "test",
    "section": "Tests",
    "hidden": true
  },
  {
    "type": "build",
    "section": "Build System",
    "hidden": true
  },
  {
    "type": "ci",
    "section": "Continuous Integration",
    "hidden": true
  }
]

major.description:
Strategy for bumping major version (x.2.3).
Default: {
  "count-breaking-as": "commit"
}

minor.description:
Strategy for bumping minor version (1.x.3).
Default: {
  "types": [
    "feat"
  ]
}

patch.description:
Strategy for bumping patch version (1.2.x).
Default: {
  "types": [
    "fix",
    "perf"
  ]
}
